arguments.new_str:
class SyncJob
{
    void Run(BlogContext context)
    {
        // Breaking change 4: EF Core 9 uses full-document updates (no patch-based).
        // Sync-all-and-save patterns now send full document replacements — no code fix
        // needed, but be aware of increased RU cost for large documents.
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        context.SaveChanges();

        // Breaking change 5: Raw SQL referencing "Discriminator" still works IF you
        // applied the HasDiscriminator("Discriminator") fix above. Otherwise queries like:
        //   SELECT * FROM c WHERE c.Discriminator = 'Blog'
        // would need to become:
        //   SELECT * FROM c WHERE c["$type"] = 'Blog'
    }
}

